public class BinarySearch {
    static int search(int[] a, int t){int lo=0,hi=a.length-1;while(lo<=hi){int m=lo+(hi-lo)/2;if(a[m]==t)return m;if(a[m]<t)lo=m+1;else hi=m-1;}return -1;}
    public static void main(String[] a){System.out.println(search(new int[]{-1,0,3,5,9,12},9));System.out.println(search(new int[]{-1,0,3,5,9,12},2));System.out.println("O(log n) — lo+(hi-lo)/2 avoids overflow. Loop condition: lo<=hi");}
}

public class FirstLast {
    static int first(int[] a,int t){int lo=0,hi=a.length-1,res=-1;while(lo<=hi){int m=lo+(hi-lo)/2;if(a[m]==t){res=m;hi=m-1;}else if(a[m]<t)lo=m+1;else hi=m-1;}return res;}
    static int last(int[] a,int t){int lo=0,hi=a.length-1,res=-1;while(lo<=hi){int m=lo+(hi-lo)/2;if(a[m]==t){res=m;lo=m+1;}else if(a[m]<t)lo=m+1;else hi=m-1;}return res;}
    public static void main(String[] a){int[] arr={5,7,7,8,8,10};System.out.println(first(arr,8)+" "+last(arr,8));System.out.println(first(arr,6)+" "+last(arr,6));System.out.println("First: when found, hi=m-1 (go left). Last: when found, lo=m+1 (go right).");}
}

public class SearchInsert {
    static int searchInsert(int[] a, int t){int lo=0,hi=a.length-1;while(lo<=hi){int m=lo+(hi-lo)/2;if(a[m]==t)return m;if(a[m]<t)lo=m+1;else hi=m-1;}return lo;}
    public static void main(String[] a){System.out.println(searchInsert(new int[]{1,3,5,6},5));System.out.println(searchInsert(new int[]{1,3,5,6},2));System.out.println(searchInsert(new int[]{1,3,5,6},7));System.out.println("Return lo when not found — lo is the correct insertion position.");}
}

public class RotatedSearch {
    static int search(int[] a, int t){int lo=0,hi=a.length-1;while(lo<=hi){int m=lo+(hi-lo)/2;if(a[m]==t)return m;if(a[lo]<=a[m]){if(a[lo]<=t&&t<a[m])hi=m-1;else lo=m+1;}else{if(a[m]<t&&t<=a[hi])lo=m+1;else hi=m-1;}}return -1;}
    public static void main(String[] a){System.out.println(search(new int[]{4,5,6,7,0,1,2},0));System.out.println(search(new int[]{4,5,6,7,0,1,2},3));System.out.println("Determine which half is sorted; check if target is in that half.");}
}

public class RotatedMin {
    static int findMin(int[] a){int lo=0,hi=a.length-1;while(lo<hi){int m=lo+(hi-lo)/2;if(a[m]>a[hi])lo=m+1;else hi=m;}return a[lo];}
    public static void main(String[] a){System.out.println(findMin(new int[]{3,4,5,1,2}));System.out.println(findMin(new int[]{4,5,6,7,0,1,2}));System.out.println(findMin(new int[]{11,13,15,17}));System.out.println("a[m]>a[hi]: min is in right half. Else: min is in left half (or m). Loop: lo<hi");}
}

public class Matrix2D {
    static boolean searchMatrix(int[][] m, int t){int r=m.length,c=m[0].length,lo=0,hi=r*c-1;while(lo<=hi){int mid=lo+(hi-lo)/2,v=m[mid/c][mid%c];if(v==t)return true;if(v<t)lo=mid+1;else hi=mid-1;}return false;}
    public static void main(String[] a){int[][] m={{1,3,5,7},{10,11,16,20},{23,30,34,60}};System.out.println(searchMatrix(m,3));System.out.println(searchMatrix(m,13));System.out.println("Treat 2D as 1D: mid/cols=row, mid%cols=col. O(log(m*n))");}
}

public class Sqrt {
    static int mySqrt(int x){if(x<2)return x;int lo=1,hi=x/2;while(lo<=hi){int m=lo+(hi-lo)/2;if((long)m*m==x)return m;if((long)m*m<x)lo=m+1;else hi=m-1;}return hi;}
    public static void main(String[] a){System.out.println(mySqrt(4));System.out.println(mySqrt(8));System.out.println(mySqrt(2147395600));System.out.println("O(log n). Use (long)m*m to avoid int overflow. Return hi (floor).");}
}

public class PeakElement {
    static int findPeakElement(int[] a){int lo=0,hi=a.length-1;while(lo<hi){int m=lo+(hi-lo)/2;if(a[m]>a[m+1])hi=m;else lo=m+1;}return lo;}
    public static void main(String[] a){System.out.println(findPeakElement(new int[]{1,2,3,1}));System.out.println(findPeakElement(new int[]{1,2,1,3,5,6,4}));System.out.println("a[m]>a[m+1]: peak in left half (including m). Else: peak in right half. O(log n).");}
}

import java.util.*;
public class KokoEating {
    static int minEatingSpeed(int[] piles, int h){int lo=1,hi=Arrays.stream(piles).max().getAsInt();while(lo<hi){int m=lo+(hi-lo)/2;if(canEat(piles,m,h))hi=m;else lo=m+1;}return lo;}
    static boolean canEat(int[] p,int k,int h){int hrs=0;for(int x:p)hrs+=(x+k-1)/k;return hrs<=h;}
    public static void main(String[] a){System.out.println(minEatingSpeed(new int[]{3,6,7,11},8));System.out.println(minEatingSpeed(new int[]{30,11,23,4,20},5));System.out.println("Binary search on answer space [1..max]. Check feasibility. O(n log max).");}
}

import java.util.*;
public class HIndex {
    static int hIndex(int[] c){Arrays.sort(c);int n=c.length,h=0;for(int i=0;i<n;i++)h=Math.max(h,Math.min(c[i],n-i));return h;}
    public static void main(String[] a){System.out.println(hIndex(new int[]{3,0,6,1,5}));System.out.println(hIndex(new int[]{1,3,1}));System.out.println("Sort: for each paper i, h-index contribution = min(citations[i], remaining papers = n-i).");}
}

public class BSSynth {
    static int rotSearch(int[] a,int t){int lo=0,hi=a.length-1;while(lo<=hi){int m=lo+(hi-lo)/2;if(a[m]==t)return m;if(a[lo]<=a[m]){if(a[lo]<=t&&t<a[m])hi=m-1;else lo=m+1;}else{if(a[m]<t&&t<=a[hi])lo=m+1;else hi=m-1;}}return -1;}
    static int koko(int[] p,int h){int lo=1,hi=0;for(int x:p)hi=Math.max(hi,x);while(lo<hi){int m=lo+(hi-lo)/2;int hrs=0;for(int x:p)hrs+=(x+m-1)/m;if(hrs<=h)hi=m;else lo=m+1;}return lo;}
    static int sqrtBS(int x){if(x<2)return x;int lo=1,hi=x/2;while(lo<=hi){int m=lo+(hi-lo)/2;if((long)m*m==x)return m;if((long)m*m<x)lo=m+1;else hi=m-1;}return hi;}
    public static void main(String[] a){System.out.println(rotSearch(new int[]{4,5,6,7,0,1,2},0));System.out.println(koko(new int[]{3,6,7,11},8));System.out.println(sqrtBS(8));boolean ok=rotSearch(new int[]{4,5,6,7,0,1,2},0)==4&&koko(new int[]{3,6,7,11},8)==4&&sqrtBS(8)==2;System.out.println("All pass: "+ok);}
}

